class Solution {
    public String crackSafe(int n, int k) {
        Set<String> visited = new HashSet<>();
        StringBuilder res = new StringBuilder();
        dfs(0, 0, n, k, visited, res);
        return "0".repeat(n - 1) + res.toString();
    }

    private void dfs(int node, int prev, int n, int k, Set<String> visited, StringBuilder res) {
        for (int i = 0; i < k; i++) {
            String cur = String.valueOf(i);
            int next = (node * k + i) % (k * (int) Math.pow(10, n - 1));
            if (!visited.contains(cur)) {
                visited.add(cur);
                res.append(i);
                dfs(next, i, n, k, visited, res);
                visited.remove(cur);
                res.deleteCharAt(res.length() - 1);
            }
        }
    }
}
